insert into public.product_categories (
  id,
  title_uk,
  title_en,
  subtitle_uk,
  subtitle_en,
  icon_key,
  sort_order
)
values
  ('aloe_drinks', 'Напої з Aloe', 'Aloe drinks', 'Aloe-гель, функціональні напої та travel-формати для щоденного ритму.', 'Aloe gels, functional drinks, and portable formats for a steady routine.', 'water_drop', 1),
  ('bee_products', 'Bee-продукти', 'Bee products', 'Мед, пилок, прополіс і маточне молочко для загальної wellness-рутини.', 'Honey, pollen, propolis, and royal jelly for a general wellness routine.', 'hive', 2),
  ('combo_packs', 'Набори та програми', 'Combo packs', 'Комбо-набори, програми та стартові рішення з Aloe Hub каталогу.', 'Combo packs, programs, and starter solutions from the Aloe Hub catalog.', 'pack', 3),
  ('supplements', 'Харчові добавки', 'Supplements', 'Daily wellness-support формати для харчування, енергії та послідовності.', 'Daily wellness-support formats for nutrition, energy, and consistency.', 'nutrition', 4),
  ('skincare', 'Догляд за шкірою', 'Skincare', 'Aloe-first креми, сироватки, тонери та спеціалізований догляд.', 'Aloe-first creams, serums, toners, and targeted care.', 'spa', 5),
  ('personal_care', 'Особиста гігієна', 'Personal care', 'Щоденні продукти для чистоти, свіжості та комфортної self-care рутини.', 'Daily essentials for freshness, hygiene, and self-care.', 'self_improvement', 6),
  ('body_care', 'Догляд за тілом', 'Body care', 'Body-care продукти для душу, тонусу та м’якого відчуття комфорту.', 'Body-care products for shower rituals, toning, and comfort.', 'body', 7),
  ('hair_care', 'Догляд за волоссям', 'Hair care', 'Шампуні та кондиціонери для щоденного догляду за волоссям.', 'Shampoos and conditioners for everyday hair care.', 'hair', 8),
  ('fragrances', 'Аромати', 'Fragrances', 'Легкі жіночі та чоловічі аромати для завершення образу.', 'Light feminine and masculine fragrances for the finishing touch.', 'fragrance', 9)
on conflict (id) do update
set
  title_uk = excluded.title_uk,
  title_en = excluded.title_en,
  subtitle_uk = excluded.subtitle_uk,
  subtitle_en = excluded.subtitle_en,
  icon_key = excluded.icon_key,
  sort_order = excluded.sort_order;

