  wellness_tags
)
values
  ('storefront-2', 'combo_packs', 'Фаворит', null, 'Фаворит як готовий wellness-набір для структурованого старту або перезапуску рутини.', null, 'Обирайте як структурований wellness-формат для старту або перезапуску щоденної рутини без медичних очікувань.', null, 'Набори поєднують кілька wellness-продуктів. Перевіряйте склад кожної позиції та обирайте формат, який підходить саме вам.', null, 'pack', 'https://aloe-hub.flpuretail.com/uk/catalog/product/121/', 'SKU 002 • Готовий набір для структурованої рутини', 'SKU 002', true, ARRAY['combo','daily-routine','self-care']::text[]),
  ('storefront-4', 'combo_packs', 'Свобода руху', null, 'Свобода руху як готовий wellness-набір для структурованого старту або перезапуску рутини.', null, 'Обирайте як структурований wellness-формат для старту або перезапуску щоденної рутини без медичних очікувань.', null, 'Набори поєднують кілька wellness-продуктів. Перевіряйте склад кожної позиції та обирайте формат, який підходить саме вам.', null, 'pack', 'https://aloe-hub.flpuretail.com/uk/catalog/product/122/', 'SKU 004 • Готовий набір для структурованої рутини', 'SKU 004', true, ARRAY['combo','daily-routine','self-care']::text[]),
  ('storefront-5', 'combo_packs', 'Кардіо здоров''я', null, 'Кардіо здоров''я як готовий wellness-набір для структурованого старту або перезапуску рутини.', null, 'Обирайте як структурований wellness-формат для старту або перезапуску щоденної рутини без медичних очікувань.', null, 'Набори поєднують кілька wellness-продуктів. Перевіряйте склад кожної позиції та обирайте формат, який підходить саме вам.', null, 'pack', 'https://aloe-hub.flpuretail.com/uk/catalog/product/123/', 'SKU 005 • Готовий набір для структурованої рутини', 'SKU 005', true, ARRAY['combo','daily-routine','self-care']::text[]),
  ('aloe-lips', 'personal_care', 'Гігієнічна Помада Алое Ліпс', 'Aloe Lips', 'Гігієнічна Помада Алое Ліпс для стабільного щоденного ритуалу особистої гігієни.', null, 'Використовуйте у щоденній ранковій або вечірній рутині догляду за собою.', null, 'Використовуйте за інструкцією виробника. У разі подразнення припиніть використання та зверніться до фахівця.', null, 'smile', 'https://aloe-hub.flpuretail.com/uk/catalog/product/126/', 'SKU 022 • Основа щоденної гігієни', 'SKU 022', true, ARRAY['self-care','daily-routine','beauty']::text[]),
  ('forever-bee-pollen', 'bee_products', 'Форевер Бджолиний пилок', 'Forever Bee Pollen', 'Форевер Бджолиний пилок як частина загальної wellness-рутини без медичних обіцянок.', null, 'Додавайте до загальної wellness-рутини поступово та з урахуванням персональної переносимості інгредієнтів.', null, 'Містить або може містити компоненти бджільництва. Якщо є чутливість або алергії, потрібна додаткова обережність.', null, 'bee', 'https://aloe-hub.flpuretail.com/uk/catalog/product/226/', 'SKU 026 • Bee-підтримка щоденного ритму', 'SKU 026', false, ARRAY['bee','energy','nutrition']::text[]),
  ('forever-bee-propolis', 'bee_products', 'Форевер Бджолиний прополіс', 'Forever Bee Propolis', 'Форевер Бджолиний прополіс як частина загальної wellness-рутини без медичних обіцянок.', null, 'Додавайте до загальної wellness-рутини поступово та з урахуванням персональної переносимості інгредієнтів.', null, 'Містить або може містити компоненти бджільництва. Якщо є чутливість або алергії, потрібна додаткова обережність.', null, 'propolis', 'https://aloe-hub.flpuretail.com/uk/catalog/product/128/', 'SKU 027 • Bee-підтримка щоденного ритму', 'SKU 027', false, ARRAY['bee','balance','daily-routine']::text[]),
  ('forever-bright-toothgel', 'personal_care', 'Зубна Паста Форевер Брайт', 'Forever Bright Toothgel', 'Зубна Паста Форевер Брайт для стабільного щоденного ритуалу особистої гігієни.', null, 'Використовуйте у щоденній ранковій або вечірній рутині догляду за собою.', null, 'Використовуйте за інструкцією виробника. У разі подразнення припиніть використання та зверніться до фахівця.', null, 'smile', 'https://aloe-hub.flpuretail.com/uk/catalog/product/129/', 'SKU 028 • Щоденна oral-care рутина', 'SKU 028', true, ARRAY['self-care','daily-routine','beauty']::text[]),
  ('storefront-28s', 'personal_care', 'Промо Зубна паста (2=3)', null, 'Промо Зубна паста (2=3) для стабільного щоденного ритуалу особистої гігієни.', null, 'Використовуйте у щоденній ранковій або вечірній рутині догляду за собою.', null, 'Використовуйте за інструкцією виробника. У разі подразнення припиніть використання та зверніться до фахівця.', null, 'smile', 'https://aloe-hub.flpuretail.com/uk/catalog/product/300/', 'SKU 028S • Основа щоденної гігієни', 'SKU 028S', false, ARRAY['self-care','daily-routine','beauty']::text[]),
  ('forever-royal-jelly', 'bee_products', 'Форевер Бджолине молочко', 'Forever Royal Jelly', 'Форевер Бджолине молочко як частина загальної wellness-рутини без медичних обіцянок.', null, 'Додавайте до загальної wellness-рутини поступово та з урахуванням персональної переносимості інгредієнтів.', null, 'Містить або може містити компоненти бджільництва. Якщо є чутливість або алергії, потрібна додаткова обережність.', null, 'bee', 'https://aloe-hub.flpuretail.com/uk/catalog/product/132/', 'SKU 036 • Bee-підтримка щоденного ритму', 'SKU 036', false, ARRAY['bee','energy','balance']::text[]),
  ('nature-min', 'supplements', 'Форевер Натур-мін', 'Nature-Min', 'Форевер Натур-мін для щоденної nutrient-focused wellness-підтримки та структурованого ритму.', null, 'Розглядайте як доповнення до харчування, сну, руху та базових щоденних звичок.', null, 'Не замінює індивідуальний план харчування або професійну медичну консультацію. Перевіряйте склад перед використанням.', null, 'shake', 'https://aloe-hub.flpuretail.com/uk/catalog/product/133/', 'SKU 037 • Доповнення до daily wellness-плану', 'SKU 037', false, ARRAY['nutrition','balance','daily-routine']::text[]),
  ('aloe-first', 'skincare', 'Алое Фьорст', 'Aloe First', 'Алое Фьорст для щоденного догляду за шкірою і м’якого self-care ритуалу.', null, 'Наносьте у межах регулярного догляду за шкірою та послідовного self-care ритуалу.', null, 'Для зовнішнього використання, якщо інше не вказано виробником. Перед регулярним використанням перевіряйте індивідуальну чутливість.', null, 'aloe', 'https://aloe-hub.flpuretail.com/uk/catalog/product/134/', 'SKU 040 • Щоденний догляд за шкірою', 'SKU 040', false, ARRAY['self-care','skin','balance']::text[]),
  ('forever-absorbent-c', 'supplements', 'Форевер Абсорбент-С', 'Forever Absorbent C', 'Форевер Абсорбент-С для щоденної nutrient-focused wellness-підтримки та структурованого ритму.', null, 'Розглядайте як доповнення до харчування, сну, руху та базових щоденних звичок.', null, 'Не замінює індивідуальний план харчування або професійну медичну консультацію. Перевіряйте склад перед використанням.', null, 'shake', 'https://aloe-hub.flpuretail.com/uk/catalog/product/135/', 'SKU 048 • Доповнення до daily wellness-плану', 'SKU 048', false, ARRAY['nutrition','balance','daily-routine']::text[]),
  ('aloe-propolis-creme', 'skincare', 'Крем Алое з прополісом', 'Aloe Propolis Creme', 'Крем Алое з прополісом для щоденного догляду за шкірою і м’якого self-care ритуалу.', null, 'Наносьте у межах регулярного догляду за шкірою та послідовного self-care ритуалу.', null, 'Для зовнішнього використання, якщо інше не вказано виробником. Перед регулярним використанням перевіряйте індивідуальну чутливість.', null, 'cream', 'https://aloe-hub.flpuretail.com/uk/catalog/product/136/', 'SKU 051 • Щоденний догляд за шкірою', 'SKU 051', true, ARRAY['beauty','skin','self-care']::text[]),
  ('aloe-vera-gelly', 'skincare', 'Желе Алое вера', 'Aloe Vera Gelly', 'Желе Алое вера для щоденного догляду за шкірою і м’якого self-care ритуалу.', null, 'Наносьте у межах регулярного догляду за шкірою та послідовного self-care ритуалу.', null, 'Для зовнішнього використання, якщо інше не вказано виробником. Перед регулярним використанням перевіряйте індивідуальну чутливість.', null, 'gelly', 'https://aloe-hub.flpuretail.com/uk/catalog/product/137/', 'SKU 061 • Щоденний догляд за шкірою', 'SKU 061', true, ARRAY['beauty','skin','self-care']::text[]),
