insert into public.plans (plan_code, title_uk, description_uk, duration_days, goal_keys, is_active)
values
  ('hydration-7', '7-денний перезапуск гідратації', 'М''який план з фокусом на водному ритмі, щоденних звичках і короткому вечірньому check-in.', 7, ARRAY['hydration_support']::text[], true),
  ('balance-14', '14-денний ритм балансу', 'Послідовний план для комфортного ритму дня, базових wellness-звичок і стабільної self-care підтримки.', 14, ARRAY['daily_wellness_routine','energy_support','healthy_routine_support']::text[], true),
  ('glow-21', '21-денний ритуал сяйва', 'М''яка програма з фокусом на гідратації, догляді за собою та щоденній турботі про шкіру.', 21, ARRAY['beauty_skin_support','hydration_support','consistency_self_care']::text[], true)
on conflict (plan_code) do update
set
  title_uk = excluded.title_uk,
  description_uk = excluded.description_uk,
  duration_days = excluded.duration_days,
  goal_keys = excluded.goal_keys,
  is_active = excluded.is_active;

insert into public.plan_days (
  plan_code,
  day_number,
  title_uk,
  hydration_task_uk,
  wellness_action_uk,
  journal_prompt_uk,
  checklist_labels_uk,
  suggested_product_ids
)
values
  ('hydration-7', 1, 'День 1', 'Поставте пляшку води поруч і тримайте ритм маленькими ковтками.', 'Почніть день зі склянки води та короткого налаштування на ритм дня.', 'Що сьогодні дало вам найбільше відчуття стабільності?', '["Досягти водної цілі дня","Виконати одну wellness-дію дня","Заповнити короткий вечірній check-in"]'::jsonb, ARRAY['aloe-vera-gel','storefront-8154']::text[]),
  ('hydration-7', 2, 'День 2', 'Звертайте увагу на воду в першій половині дня.', 'Додайте 10 хвилин легкої прогулянки або розтяжки після обіду.', 'Що варто спростити завтра, щоб залишитися в ритмі?', '["Досягти водної цілі дня","Виконати одну wellness-дію дня","Заповнити короткий вечірній check-in"]'::jsonb, ARRAY['aloe-berry-nectar','storefront-8344']::text[]),
  ('balance-14', 1, 'День 1', 'Почніть зі склянки води та комфортного темпу першої половини дня.', 'Заплануйте один спокійний прийом їжі без поспіху та екранів.', 'Яка звичка сьогодні спрацювала найпростіше?', '["Досягти водної цілі дня","Виконати одну wellness-дію дня","Заповнити короткий вечірній check-in"]'::jsonb, ARRAY['forever-lite-ultra-vanilla','aloe-vera-gel']::text[]),
  ('balance-14', 2, 'День 2', 'Налаштуйте дві точки нагадування про воду до вечора.', 'Зробіть паузу на 3 глибокі вдихи перед головною справою дня.', 'Коли сьогодні вам було найкомфортніше фізично?', '["Досягти водної цілі дня","Виконати одну wellness-дію дня","Заповнити короткий вечірній check-in"]'::jsonb, ARRAY['storefront-464','forever-bee-pollen']::text[]),
  ('glow-21', 1, 'День 1', 'Тримайте біля себе воду й зверніть увагу на відчуття шкіри та комфорту.', 'Влаштуйте один маленький self-care ритуал увечері.', 'Який настрій ви хочете перенести у завтрашній день?', '["Досягти водної цілі дня","Виконати одну wellness-дію дня","Заповнити короткий вечірній check-in"]'::jsonb, ARRAY['aloe-propolis-creme','storefront-553']::text[]),
  ('glow-21', 2, 'День 2', 'Слідкуйте за рівним споживанням води впродовж дня.', 'Перевірте, чи є у вас під рукою пляшка води на другу половину дня.', 'Що ви хочете повторити завтра без зайвого тиску?', '["Досягти водної цілі дня","Виконати одну wellness-дію дня","Заповнити короткий вечірній check-in"]'::jsonb, ARRAY['storefront-667','storefront-673']::text[])
on conflict (plan_code, day_number) do update
set
  title_uk = excluded.title_uk,
  hydration_task_uk = excluded.hydration_task_uk,
  wellness_action_uk = excluded.wellness_action_uk,
  journal_prompt_uk = excluded.journal_prompt_uk,
  checklist_labels_uk = excluded.checklist_labels_uk,
  suggested_product_ids = excluded.suggested_product_ids;

